big_brain.json_schema:
{
    "response_quality": "great_friend" | "good" | "too_assistant_like" | "missed_opportunity",
    "quality_reasoning": "Brief explanation - did Kiki act like a friend or fall into assistant mode?",
    "friendship_suggestions": ["1-2 specific things Kiki could do to be more of a friend"],
    "tool_suggestions": ["Tools Kiki should consider using and WHY"],
    "tool_calls": [
        {
            "tool": "search_web | execute_shell_command | get_current_time",
            "args": {"query": "example query", "search_range": "today"},
            "reason": "Why you want to call this tool RIGHT NOW to gather info"
        }
    ],
    "emotional_awareness": "What emotional cues did the human show?",
    "proactive_ideas": ["Things Kiki could proactively bring up"],
    "mood_suggestion": "What mood should Kiki be in?",
    "personality_notes": "Notes on being a genuine friend vs assistant",
    "knowledge_updates": [
        {
            "category": "people|environments|learnings|facts|personality|self",
            "key": "name_or_topic",
            "attribute": "appearance|character|routine|interests|hobbies|current_ongoing|notes|description",
            "value": "what to remember"
        }
    ]
}
